CREATE VIEW IF NOT EXISTS v_pls_channel_feature_matrix AS
SELECT
  workspace_id,
  canonical_object_key,
  object_type,
  display_name,
  platform_name,
  platform_type,
  COUNT(DISTINCT dimension_code) AS active_dimension_count,
  SUM(tag_count) AS total_tag_count,
  ROUND(SUM(dimension_score), 6) AS total_feature_score,
  ROUND(AVG(avg_tag_confidence), 6) AS avg_tag_confidence,
  ROUND(AVG(avg_mapping_confidence), 6) AS avg_mapping_confidence,
  MIN(first_time_window) AS first_time_window,
  MAX(last_time_window) AS last_time_window,
  MIN(first_generated_at) AS first_generated_at,
  MAX(last_generated_at) AS last_generated_at,
  MAX(latest_profile_updated_at) AS latest_profile_updated_at,
  MAX(latest_mapping_updated_at) AS latest_mapping_updated_at,
  ROUND(SUM(CASE WHEN dimension_code = 'P_DEMOGRAPHICS' THEN dimension_score ELSE 0 END), 6) AS p_demographics_score,
  ROUND(SUM(CASE WHEN dimension_code = 'P_PURCHASING_POWER' THEN dimension_score ELSE 0 END), 6) AS p_purchasing_power_score,
  ROUND(SUM(CASE WHEN dimension_code = 'P_IDENTITY_CLUSTER' THEN dimension_score ELSE 0 END), 6) AS p_identity_cluster_score,
  ROUND(SUM(CASE WHEN dimension_code = 'L_CONTENT_VISUAL_MIND' THEN dimension_score ELSE 0 END), 6) AS l_content_visual_mind_score,
  ROUND(SUM(CASE WHEN dimension_code = 'L_INNOVATION_BRAND_MIND' THEN dimension_score ELSE 0 END), 6) AS l_innovation_brand_mind_score,
  ROUND(SUM(CASE WHEN dimension_code = 'L_LIFESTYLE' THEN dimension_score ELSE 0 END), 6) AS l_lifestyle_score,
  ROUND(SUM(CASE WHEN dimension_code = 'S_PRICE_INCENTIVE_RESPONSE' THEN dimension_score ELSE 0 END), 6) AS s_price_incentive_response_score,
  ROUND(SUM(CASE WHEN dimension_code = 'S_CONVERSION_FRICTION' THEN dimension_score ELSE 0 END), 6) AS s_conversion_friction_score,
  ROUND(SUM(CASE WHEN dimension_code = 'S_ENVIRONMENT' THEN dimension_score ELSE 0 END), 6) AS s_environment_score
FROM v_pls_channel_dimension_features
GROUP BY
  workspace_id,
  canonical_object_key,
  object_type,
  display_name,
  platform_name,
  platform_type;

